import { mkdtemp, readFile, rm } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { afterEach, describe, expect, it } from 'vitest';

import { createThothOathFileLedgerStore } from '../src/thoth-oath-ledger-file-store';
import {
  THOTH_OATH_PROPOSE_TOOL,
  createThothOathSelfManagementMcpClient,
} from '../src/thoth-oath-tools';

describe('ThothOathFileLedgerStore', () => {
  let tempDir: string | undefined;

  afterEach(async () => {
    if (tempDir) {
      await rm(tempDir, { recursive: true, force: true });
      tempDir = undefined;
    }
  });

  it('persists oath records to a JSON ledger file', async () => {
    tempDir = await mkdtemp(join(tmpdir(), 'thoth-oath-ledger-'));
    const ledgerPath = join(tempDir, 'nested', 'oaths.json');
    const store = createThothOathFileLedgerStore(ledgerPath);
    const client = createThothOathSelfManagementMcpClient({
      now: () => 0,
      randomId: (prefix) => `${prefix}_file`,
      ledgerStore: store,
    });

    await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'persist to host file adapter',
      durationTicks: 1,
    });

    const raw = await readFile(ledgerPath, 'utf8');
    expect(raw).toContain('persist to host file adapter');
    expect(await store.load()).toHaveLength(1);
  });

  it('loads an absent ledger as an empty record set', async () => {
    tempDir = await mkdtemp(join(tmpdir(), 'thoth-oath-ledger-'));
    const store = createThothOathFileLedgerStore(join(tempDir, 'missing.json'));

    await expect(store.load()).resolves.toEqual([]);
  });
});
